import socket
import threading
import json

class GameServer:
    def __init__(self, host='0.0.0.0', port=12345):
        self.server_address = (host, port)
        self.players = ['Player1', 'Player2', 'Player3']
        self.game_state = 'Running'
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind(self.server_address)
        self.lock = threading.Lock()

    def handle_request(self, data, address):
        try:
            request = json.loads(data.decode('utf-8'))
            if request.get('action') == 'status':
                response = {
                    'players': self.players,
                    'game_state': self.game_state
                }
                response_data = json.dumps(response).encode('utf-8')
                if len(response_data) > 512:
                    response_data = response_data[:512]  # Truncate to prevent amplification
                self.sock.sendto(response_data, address)
        except json.JSONDecodeError:
            pass

    def start(self):
        print(f"Game server running on {self.server_address}")
        while True:
            data, address = self.sock.recvfrom(1024)
            threading.Thread(target=self.handle_request, args=(data, address)).start()

if __name__ == "__main__":
    server = GameServer()
    server.start()